<?php declare(strict_types=1); namespace App\Http\Controllers\Btaq; use App\Http\Controllers\Controller; use App\Models\{BtaqGroup,BtaqSchedule,Employee}; use Illuminate\Http\Request; final class BtaqScheduleController extends Controller{public function index(){return view('btaq.schedules.index',['schedules'=>BtaqSchedule::with('group','teacher')->latest()->paginate(15)]);} public function create(){return view('btaq.schedules.form',['schedule'=>new BtaqSchedule,'groups'=>BtaqGroup::where('is_active',true)->get(),'employees'=>Employee::where('is_active',true)->get()]);} public function store(Request $r){$d=$this->data($r);$this->guardConflict($d);$s=BtaqSchedule::create($d);activity('btaq')->performedOn($s)->event('btaq.schedule.created')->log('Jadwal BTAQ dibuat');return redirect()->route('btaq-schedules.show',$s)->with('status','Jadwal BTAQ disimpan.');} public function show(BtaqSchedule $btaqSchedule){return view('btaq.schedules.show',['schedule'=>$btaqSchedule]);} public function edit(BtaqSchedule $btaqSchedule){return view('btaq.schedules.form',['schedule'=>$btaqSchedule,'groups'=>BtaqGroup::get(),'employees'=>Employee::where('is_active',true)->get()]);} public function update(Request $r,BtaqSchedule $btaqSchedule){$d=$this->data($r);$this->guardConflict($d,$btaqSchedule->id);$btaqSchedule->update($d);return redirect()->route('btaq-schedules.show',$btaqSchedule)->with('status','Jadwal BTAQ diperbarui.');} public function toggle(BtaqSchedule $btaqSchedule){$btaqSchedule->update(['is_active'=>!$btaqSchedule->is_active]);return back()->with('status','Status jadwal diperbarui.');} private function data(Request $r):array{return $r->validate(['btaq_group_id'=>'required|exists:btaq_groups,id','day_of_week'=>'required|integer|min:1|max:7','start_time'=>'required','end_time'=>'required|after:start_time','room'=>'nullable|string|max:100','teacher_employee_id'=>'required|exists:employees,id','effective_start_date'=>'nullable|date','effective_end_date'=>'nullable|date|after_or_equal:effective_start_date','is_active'=>'nullable|boolean','notes'=>'nullable|string']);} private function guardConflict(array $d,?int $ignore=null):void{$q=BtaqSchedule::where('day_of_week',$d['day_of_week'])->where('is_active',true)->where('start_time','<',$d['end_time'])->where('end_time','>',$d['start_time'])->when($ignore,fn($q)=>$q->whereKeyNot($ignore)); abort_if((clone $q)->where('teacher_employee_id',$d['teacher_employee_id'])->exists(),422,'Jadwal guru BTAQ bertabrakan.'); abort_if((clone $q)->where('btaq_group_id',$d['btaq_group_id'])->exists(),422,'Jadwal kelompok BTAQ bertabrakan.'); if(($d['room']??null)) abort_if((clone $q)->where('room',$d['room'])->exists(),422,'Ruangan BTAQ bertabrakan.');}}
